#include <stdio.h>

int gcd(int a, int b) {
    while (b != 0) {
        int t = b;
        b = a % b;
        a = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int nums[55];
        for (int i = 0; i < N; ++i) {
            scanf("%d", &nums[i]);
        }
        int g = nums[0];
        for (int i = 1; i < N; ++i) {
            g = gcd(g, nums[i]);
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", nums[i] / g);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

